sql:
SELECT category_id, COUNT(item_id) AS item_count
FROM menu_items
GROUP BY category_id;

SELECT menu_items.item_name, menu_items.item_price, item_sales.sale_date, item_sales.total_price
FROM menu_items
INNER JOIN item_sales ON menu_items.item_id = item_sales.item_id;

SELECT DISTINCT users.user_name, users.email
FROM users
JOIN item_sales ON users.user_id = item_sales.customer_id;

external_knowledge:
- "bustling intersections" refers to the combination of category and location;
- "culinary delights" metaphorically describes the menu items;
- "embarks on its journey" and "frequency of their voyages" refers to sales occurrences;
- "venues" are the locations where the items are sold.

sql:
SELECT customer_id, COUNT(*) AS purchase_count
FROM item_sales
GROUP BY customer_id;

SELECT * 
FROM menu_items 
WHERE item_id = 1;

external_knowledge:
- 'main dining area' refers to 'Central Location';
- 'since the start of the year' implies starting from January 1, 2023;
- 'burritos' refer to items categorized under 'Burrito'.

sql:
SELECT mi.item_name, i.total_price
FROM menu_items mi
JOIN item_sales i ON mi.item_id = i.item_id;

SELECT item_name
FROM menu_items
WHERE item_price = (
    SELECT MAX(item_price)
    FROM menu_items
);

SELECT mi.item_name, l.location_name
FROM menu_items AS mi
JOIN locations AS l ON mi.location_id = l.location_id;
